        const dist = new Array(n).fill(INF);
        dist[src] = 0;
        const inQueue = new Array(n).fill(false);
        const prevEdge = new Array(n).fill(-1);
        const prevNode = new Array(n).fill(-1);
        const q: number[] = [src];
        inQueue[src] = true;
        let qi = 0;

        while (qi < q.length) {
            const u = q[qi++];
            inQueue[u] = false;
            for (let e = head[u]; e !== -1; e = nxt[e]) {
                const v = to[e];
                if (cap[e] > 0 && dist[u] + cost[e] < dist[v]) {
                    dist[v] = dist[u] + cost[e];
                    prevEdge[v] = e;
                    prevNode[v] = u;
                    if (!inQueue[v]) {
                        q.push(v);
                        inQueue[v] = true;
                    }
                }
            }
        }

        if (dist[sink] === INF) break;

        let bottleneck = INF;
        for (let v = sink; v !== src; v = prevNode[v]) {
            bottleneck = Math.min(bottleneck, cap[prevEdge[v]]);
        }

        for (let v = sink; v !== src; v = prevNode[v]) {
            const e = prevEdge[v];
            cap[e] -= bottleneck;
            cap[e ^ 1] += bottleneck;
        }

        totalCost += bottleneck * dist[sink];
    }

    return totalCost;
}
